// src/main/java/com/ecommerce/search/service/SearchQueryService.java
package com.ecommerce.search.service;

import com.ecommerce.search.dto.FacetEntry;
import com.ecommerce.search.model.SearchQuery;
import com.fasterxml.jackson.databind.ObjectMapper;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.elasticsearch.action.index.IndexRequest;
import org.elasticsearch.action.search.SearchRequest;
import org.elasticsearch.action.search.SearchResponse;
import org.elasticsearch.action.update.UpdateRequest;
import org.elasticsearch.client.RequestOptions;
import org.elasticsearch.client.RestHighLevelClient;
import org.elasticsearch.common.xcontent.XContentType;
import org.elasticsearch.index.query.QueryBuilders;
import org.elasticsearch.search.aggregations.AggregationBuilders;
import org.elasticsearch.search.aggregations.bucket.histogram.DateHistogramInterval;
import org.elasticsearch.search.aggregations.bucket.histogram.Histogram;
import org.elasticsearch.search.aggregations.bucket.terms.Terms;
import org.elasticsearch.search.aggregations.metrics.Avg;
import org.elasticsearch.search.builder.SearchSourceBuilder;
import org.elasticsearch.search.sort.SortOrder;
import org.springframework.scheduling.annotation.Async;
import org.springframework.stereotype.Service;

import java.io.IOException;
import java.time.LocalDateTime;
import java.util.*;
import java.util.stream.Collectors;

import static com.ecommerce.search.service.IndexManagementService.SEARCH_QUERY_INDEX;

@Service
@RequiredArgsConstructor
@Slf4j
public class SearchQueryService {

    private final RestHighLevelClient client;
    private final ObjectMapper objectMapper;

    @Async
    public void logSearchQuery(SearchQuery searchQuery) {
        try {
            if (searchQuery.getId() == null) {
                searchQuery.setId(UUID.randomUUID().toString());
            }
            if (searchQuery.getTimestamp() == null) {
                searchQuery.setTimestamp(LocalDateTime.now());
            }

            String jsonString = objectMapper.writeValueAsString(searchQuery);

            IndexRequest request = new IndexRequest(SEARCH_QUERY_INDEX)
                    .id(searchQuery.getId())
                    .source(jsonString, XContentType.JSON);

            client.index(request, RequestOptions.DEFAULT);
            log.debug("Search query logged: {}", searchQuery.getQueryText());
        } catch (IOException e) {
            log.error("Failed to log search query", e);
        }
    }

    public void recordClick(String searchQueryId, String productId) throws IOException {
        Map<String, Object> updates = new HashMap<>();
        updates.put("clickedResult", true);
        updates.put("clickedProductId", productId);

        UpdateRequest request = new UpdateRequest(SEARCH_QUERY_INDEX, searchQueryId)
                .doc(updates);

        client.update(request, RequestOptions.DEFAULT);
        log.info("Click recorded: queryId={}, productId={}", searchQueryId, productId);
    }

    public List<FacetEntry> getPopularSearches(int size) throws IOException {
        SearchRequest esRequest = new SearchRequest(SEARCH_QUERY_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        sourceBuilder.aggregation(
                AggregationBuilders.terms("popular_searches")
                        .field("queryText.keyword")
                        .size(size)
        );

        esRequest.source(sourceBuilder);
        SearchResponse esResponse = client.search(esRequest, RequestOptions.DEFAULT);

        Terms popularTerms = esResponse.getAggregations().get("popular_searches");
        return popularTerms.getBuckets().stream()
                .map(bucket -> FacetEntry.builder()
                        .key(bucket.getKeyAsString())
                        .count(bucket.getDocCount())
                        .build())
                .collect(Collectors.toList());
    }

    public List<FacetEntry> getTrendingSearches(int hours, int size) throws IOException {
        SearchRequest esRequest = new SearchRequest(SEARCH_QUERY_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        sourceBuilder.query(QueryBuilders.rangeQuery("timestamp")
                .gte("now-" + hours + "h"));

        sourceBuilder.aggregation(
                AggregationBuilders.terms("trending_searches")
                        .field("queryText.keyword")
                        .size(size)
        );

        esRequest.source(sourceBuilder);
        SearchResponse esResponse = client.search(esRequest, RequestOptions.DEFAULT);

        Terms trendingTerms = esResponse.getAggregations().get("trending_searches");
        return trendingTerms.getBuckets().stream()
                .map(bucket -> FacetEntry.builder()
                        .key(bucket.getKeyAsString())
                        .count(bucket.getDocCount())
                        .build())
                .collect(Collectors.toList());
    }

    public Map<String, Object> getSearchAnalytics() throws IOException {
        SearchRequest esRequest = new SearchRequest(SEARCH_QUERY_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.size(0);

        // Total searches
        sourceBuilder.query(QueryBuilders.matchAllQuery());

        // Avg response time
        sourceBuilder.aggregation(
                AggregationBuilders.avg("avg_response_time")
                        .field("responseTimeMs")
        );

        // Avg results count
        sourceBuilder.aggregation(
                AggregationBuilders.avg("avg_results_count")
                        .field("resultsCount")
        );

        // Click-through rate
        sourceBuilder.aggregation(
                AggregationBuilders.terms("click_through")
                        .field("clickedResult")
                        .size(2)
        );

        // Zero-result searches
        sourceBuilder.aggregation(
                AggregationBuilders.filter("zero_results",
                        QueryBuilders.termQuery("resultsCount", 0))
        );

        // Top searched queries
        sourceBuilder.aggregation(
                AggregationBuilders.terms("top_queries")
                        .field("queryText.keyword")
                        .size(20)
        );

        // Searches by customer
        sourceBuilder.aggregation(
                AggregationBuilders.terms("searches_by_customer")
                        .field("customerId")
                        .size(10)
        );

        esRequest.source(sourceBuilder);
        SearchResponse esResponse = client.search(esRequest, RequestOptions.DEFAULT);

        Map<String, Object> analytics = new LinkedHashMap<>();
        analytics.put("totalSearches", esResponse.getHits().getTotalHits().value);

        Avg avgResponseTime = esResponse.getAggregations().get("avg_response_time");
        analytics.put("avgResponseTimeMs", avgResponseTime.getValue());

        Avg avgResultsCount = esResponse.getAggregations().get("avg_results_count");
        analytics.put("avgResultsCount", avgResultsCount.getValue());

        org.elasticsearch.search.aggregations.bucket.filter.Filter zeroResults =
                esResponse.getAggregations().get("zero_results");
        analytics.put("zeroResultSearches", zeroResults.getDocCount());

        Terms topQueries = esResponse.getAggregations().get("top_queries");
        analytics.put("topQueries", topQueries.getBuckets().stream()
                .map(b -> Map.of("query", b.getKeyAsString(), "count", b.getDocCount()))
                .collect(Collectors.toList()));

        Terms clickThrough = esResponse.getAggregations().get("click_through");
        long clickedCount = 0;
        long notClickedCount = 0;
        for (Terms.Bucket bucket : clickThrough.getBuckets()) {
            if ("true".equals(bucket.getKeyAsString())) {
                clickedCount = bucket.getDocCount();
            } else {
                notClickedCount = bucket.getDocCount();
            }
        }
        long totalWithCtr = clickedCount + notClickedCount;
        double ctr = totalWithCtr > 0 ? (double) clickedCount / totalWithCtr * 100 : 0;
        analytics.put("clickThroughRate", String.format("%.2f%%", ctr));

        return analytics;
    }

    public List<SearchQuery> getCustomerSearchHistory(String customerId, int size) throws IOException {
        SearchRequest esRequest = new SearchRequest(SEARCH_QUERY_INDEX);
        SearchSourceBuilder sourceBuilder = new SearchSourceBuilder();
        sourceBuilder.query(QueryBuilders.termQuery("customerId", customerId));
        sourceBuilder.sort("timestamp", SortOrder.DESC);
        sourceBuilder.size(size);

        esRequest.source(sourceBuilder);
        SearchResponse esResponse = client.search(esRequest, RequestOptions.DEFAULT);

        List<SearchQuery> queries = new ArrayList<>();
        for (var hit : esResponse.getHits().getHits()) {
            SearchQuery query = objectMapper.readValue(hit.getSourceAsString(), SearchQuery.class);
            query.setId(hit.getId());
            queries.add(query);
        }
        return queries;
    }
}

