// src/main/java/com/ecommerce/search/controller/ProductController.java
package com.ecommerce.search.controller;

import com.ecommerce.search.dto.BulkIndexResponse;
import com.ecommerce.search.model.Product;
import com.ecommerce.search.service.ProductIndexingService;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import java.io.IOException;
import java.util.List;
import java.util.Map;

@RestController
@RequestMapping("/api/products")
@RequiredArgsConstructor
public class ProductController {

    private final ProductIndexingService productIndexingService;

    @PostMapping
    public ResponseEntity<Product> indexProduct(@RequestBody Product product) throws IOException {
        Product indexed = productIndexingService.indexProduct(product);
        return ResponseEntity.status(HttpStatus.CREATED).body(indexed);
    }

    @PostMapping("/bulk")
    public ResponseEntity<BulkIndexResponse> bulkIndexProducts(@RequestBody List<Product> products) throws IOException {
        BulkIndexResponse response = productIndexingService.bulkIndexProducts(products);
        return ResponseEntity.ok(response);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Product> getProduct(@PathVariable String id) throws IOException {
        Product product = productIndexingService.getProduct(id);
        if (product == null) {
            return ResponseEntity.notFound().build();
        }
        return ResponseEntity.ok(product);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Product> updateProduct(@PathVariable String id, @RequestBody Product product) throws IOException {
        Product updated = productIndexingService.updateProduct(id, product);
        return ResponseEntity.ok(updated);
    }

    @PatchMapping("/{id}")
    public ResponseEntity<Product> partialUpdateProduct(@PathVariable String id, @RequestBody Map<String, Object> updates) throws IOException {
        Product updated = productIndexingService.partialUpdateProduct(id, updates);
        return ResponseEntity.ok(updated);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteProduct(@PathVariable String id) throws IOException {
        boolean deleted = productIndexingService.deleteProduct(id);
        if (deleted) {
            return ResponseEntity.noContent().build();
        }
        return ResponseEntity.notFound().build();
    }

    @DeleteMapping("/bulk")
    public ResponseEntity<BulkIndexResponse> bulkDeleteProducts(@RequestBody List<String> ids) throws IOException {
        BulkIndexResponse response = productIndexingService.bulkDeleteProducts(ids);
        return ResponseEntity.ok(response);
    }
}

